import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Zap, Search } from 'lucide-react';
import { Link } from 'react-router-dom';
import { NAV_ITEMS } from '../constants';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // If the click is not on a dropdown button, close menus
      if (!(event.target as HTMLElement).closest('button[data-menu-trigger]')) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    // Prevent the document click listener from firing immediately
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/95 backdrop-blur-md shadow-md py-3' : 'bg-white py-5'
        }`}
    >
      {/* Added 'relative' to the container to position absolute mega-menus correctly */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between">

          {/* Logo on Left */}
          <Link to="/" className="flex-shrink-0 flex items-center gap-2 cursor-pointer group">
            <img src="https://www.gnjworldwide.com/Logo.png" className="h-12 w-auto" alt="GnJ Worldwide Logo" />
            <span className="font-bold text-xl tracking-tight text-slate-900 group-hover:text-slate-700 transition-colors">
              GnJ<span className="text-yellow-500">Worldwide</span>
            </span>
          </Link>

          {/* Menu Items in Center */}
          <div className="hidden lg:flex items-center justify-center flex-1 mx-8">
            <div className="flex items-center gap-2">
              {NAV_ITEMS.map((item) => (
                <div
                  key={item.title}
                  // Use 'static' for megaMenu items so they position relative to the main container
                  // Use 'relative' for regular dropdowns so they position relative to the item
                  className={item.megaMenu ? "static" : "relative"}
                >
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-[15px] font-medium transition-colors duration-200 ${activeSubmenu === item.title
                        ? 'text-slate-900 bg-slate-100'
                        : 'text-slate-600 hover:text-slate-900 hover:bg-slate-100'
                        }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1.5 w-4 h-4 transition-transform duration-200 ${activeSubmenu === item.title ? 'rotate-180 text-slate-900' : 'text-slate-400'
                          }`}
                      />
                    </button>
                  ) : (
                    <a
                      href={item.href}
                      className="flex items-center px-4 py-2 text-[15px] font-medium text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors"
                    >
                      {item.title}
                    </a>
                  )}

                  {/* Mega Menu Dropdown */}
                  {item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 w-full pt-4 z-50 animate-slide-down">
                      <div className="bg-white shadow-2xl rounded-2xl border border-slate-100 overflow-hidden">
                        <div className="flex flex-row p-8 gap-8">

                          {/* Columns */}
                          <div className="flex-1 grid grid-cols-5 gap-8">
                            {item.megaMenu.columns.map((column, idx) => (
                              <div key={idx} className="space-y-6">
                                {column.groups ? (
                                  // Render multiple groups in one column
                                  column.groups.map((group, gIdx) => (
                                    <div key={gIdx} className="space-y-4">
                                      {group.title ? (
                                        group.titleHref ? (
                                          <Link to={group.titleHref} onClick={() => setActiveSubmenu(null)} className="text-[15px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block hover:text-blue-600 transition-colors">
                                            {group.title}
                                          </Link>
                                        ) : (
                                          <h4 className="text-[15px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block">
                                            {group.title}
                                          </h4>
                                        )
                                      ) : group.title === "" ? (
                                        // Render spacer if empty string
                                        <h4 className="text-[15px] font-bold text-transparent border-b-2 border-transparent pb-1 inline-block select-none" aria-hidden="true">
                                          &nbsp;
                                        </h4>
                                      ) : null /* Render nothing if undefined/null */}

                                      <ul className="space-y-2.5">
                                        {group.items.map((subItem, sIdx) => (
                                          <li key={sIdx}>
                                            <a
                                              href={subItem.href}
                                              className="text-[14px] text-slate-600 hover:text-blue-600 transition-colors block"
                                            >
                                              {subItem.title}
                                            </a>
                                          </li>
                                        ))}
                                      </ul>
                                    </div>
                                  ))
                                ) : (
                                  // Render standard single column
                                  <div className="space-y-4">
                                    {column.title ? (
                                      column.titleHref ? (
                                        <Link to={column.titleHref} onClick={() => setActiveSubmenu(null)} className="text-[15px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block hover:text-blue-600 transition-colors">
                                          {column.title}
                                        </Link>
                                      ) : (
                                        <h4 className="text-[15px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block">
                                          {column.title}
                                        </h4>
                                      )
                                    ) : column.title === "" ? (
                                      /* Spacer for alignment if empty string */
                                      <h4 className="text-[15px] font-bold text-transparent border-b-2 border-transparent pb-1 inline-block select-none" aria-hidden="true">
                                        &nbsp;
                                      </h4>
                                    ) : null /* Render nothing if undefined/null */}

                                    <ul className="space-y-2.5">
                                      {column.items?.map((subItem, sIdx) => (
                                        <li key={sIdx}>
                                          <a
                                            href={subItem.href}
                                            className="text-[14px] text-slate-600 hover:text-blue-600 transition-colors block"
                                          >
                                            {subItem.title}
                                          </a>
                                        </li>
                                      ))}
                                    </ul>
                                  </div>
                                )}
                              </div>
                            ))}
                          </div>

                          {/* Close Button (Optional based on design) */}
                          <button
                            onClick={(e) => { e.stopPropagation(); setActiveSubmenu(null); }}
                            className="absolute top-6 right-4 text-slate-400 hover:text-slate-600 transition-colors"
                          >
                            <X size={20} />
                          </button>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* Regular Dropdown (Services/Simple) */}
                  {item.children && !item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 py-2 z-50">
                      {item.children.map((subItem) => (
                        <a
                          key={subItem.title}
                          href={subItem.href}
                          className="block px-4 py-2.5 text-sm text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors"
                        >
                          {subItem.title}
                        </a>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right Side Actions (Search + Contact) */}
          <div className="hidden lg:flex items-center gap-3">
            <button
              className="p-2.5 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            <button className="relative overflow-hidden group bg-yellow-400 hover:bg-yellow-500 text-white font-bold p-3  transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-[0_8px_20px_-6px_rgba(250,204,21,0.6)] active:translate-y-0 active:shadow-none">
              <span className="relative z-10 flex items-center">
                Contact Us
              </span>
              <div className="absolute top-0 left-[-100%] w-[40%] h-full bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-[-20deg] group-hover:animate-shimmer"></div>
            </button>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2">
            <button
              className="p-2 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={22} />
            </button>

            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50 bg-white">
          <div className="flex flex-col h-full">
            <div className="flex items-center justify-between p-4 border-b border-gray-100">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-black text-white rounded-lg flex items-center justify-center">
                  <Zap size={18} fill="currentColor" />
                </div>
                <span className="font-bold text-lg text-slate-900">Nova<span className="text-yellow-500">Tech</span></span>
              </div>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"
              >
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto py-4 px-4 space-y-2">
              {NAV_ITEMS.map((item) => (
                <div key={item.title} className="border-b border-gray-50 last:border-0 pb-2">
                  <div
                    className="flex items-center justify-between w-full px-4 py-3 text-base font-semibold text-slate-800 rounded-xl hover:bg-slate-50 cursor-pointer active:bg-slate-100 transition-colors"
                    onClick={() => {
                      if (item.children || item.megaMenu) {
                        setActiveSubmenu(activeSubmenu === item.title ? null : item.title);
                      }
                    }}
                  >
                    <span>{item.title}</span>
                    {(item.children || item.megaMenu) && (
                      <ChevronDown
                        className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : ''}`}
                      />
                    )}
                  </div>

                  {/* Mobile Submenu Rendering */}
                  {activeSubmenu === item.title && (
                    <div className="pl-4 pr-2 py-2 space-y-1">
                      {/* Handle Mega Menu Items for Mobile */}
                      {item.megaMenu ? (
                        item.megaMenu.columns.map((col, idx) => (
                          <div key={idx} className="mb-4">
                            {/* Handle Grouped Columns in Mobile */}
                            {col.groups ? (
                              col.groups.map((group, gIdx) => (
                                <div key={gIdx} className="mb-4">
                                  {group.title && (
                                     group.titleHref ? (
                                      <Link to={group.titleHref} onClick={() => setIsMobileMenuOpen(false)} className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 hover:text-blue-600">
                                        {group.title}
                                      </Link>
                                     ) : (
                                       <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{group.title}</h5>
                                     )
                                  )}
                                  {group.items.map(subItem => (
                                    <a
                                      key={subItem.title}
                                      href={subItem.href}
                                      className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                    >
                                      {subItem.title}
                                    </a>
                                  ))}
                                </div>
                              ))
                            ) : (
                              <>
                                {col.title && (
                                   col.titleHref ? (
                                      <Link to={col.titleHref} onClick={() => setIsMobileMenuOpen(false)} className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 hover:text-blue-600">
                                        {col.title}
                                      </Link>
                                   ) : (
                                      <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{col.title}</h5>
                                   )
                                )}
                                {col.items?.map(subItem => (
                                  <a
                                    key={subItem.title}
                                    href={subItem.href}
                                    className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                  >
                                    {subItem.title}
                                  </a>
                                ))}
                              </>
                            )}
                          </div>
                        ))
                      ) : (
                        item.children?.map((subItem) => (
                          <a
                            key={subItem.title}
                            href={subItem.href}
                            className="flex items-center p-3 text-sm font-medium text-slate-600 rounded-lg hover:bg-yellow-50 hover:text-slate-900 transition-colors"
                          >
                            {subItem.title}
                          </a>
                        ))
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-4 border-t border-gray-100">
              <button className="w-full flex justify-center items-center bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold py-4 rounded-2xl transition-all shadow-lg active:scale-95">
                Contact Us <ArrowRight className="ml-2 w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

