  useEffect(() => {
    if (!isAutoPlaying) return;

    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % SLIDES.length);
    }, 6000);

    return () => clearInterval(interval);
  }, [isAutoPlaying]);

  const setSlide = (index: number) => {
    setCurrentSlide(index);
    setIsAutoPlaying(false);
