                {slide.subtitle}
              </p>

              <div className="flex flex-wrap gap-4">
                <button 
                  className={`${slide.buttonColor} text-white px-8 py-4 rounded-full font-bold text-lg transition-all shadow-lg hover:shadow-xl hover:-translate-y-1 flex items-center group`}
