                </div>
                <span className="font-bold text-lg text-slate-900">Nova<span className="text-yellow-500">Tech</span></span>
              </div>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"
