const DynamicPage: React.FC = () => {
  const location = useLocation();
  const path = location.pathname;
  // Normalize path to handle potential trailing slashes if needed, though exact match is best for the map key
  const data = PAGE_DATA[path];

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [path]);

  if (!data) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center bg-slate-50 px-4 text-center">
        <h1 className="text-6xl font-bold text-slate-200 mb-4">404</h1>
        <h2 className="text-2xl font-bold text-slate-800 mb-4">Page Not Found</h2>
        <p className="text-slate-600 mb-8 max-w-md">
          The page you are looking for ({path}) does not exist or is currently under construction.
        </p>
        <Link to="/" className="bg-blue-600 text-white px-6 py-3 rounded-lg font-semibold hover:bg-blue-700 transition-colors inline-flex items-center">
          Go Home <ArrowRight className="ml-2 w-4 h-4" />
        </Link>
      </div>
    );
  }

  return (
    <div className="bg-white">
      {/* Hero Section */}
      <div className="relative h-[400px] md:h-[500px] flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img 
            src={data.heroImage} 
            alt={data.title} 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-slate-900/60 mix-blend-multiply" />
        </div>

        <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center text-white">
          <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold mb-6 animate-fade-in tracking-tight">
            {data.title}
          </h1>
          <p className="text-lg md:text-xl max-w-2xl mx-auto text-slate-200 animate-slide-down">
            {data.subtitle}
          </p>
        </div>
      </div>

      {/* Content Sections */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20">
        {data.sections.map((section, index) => (
          <div 
            key={index} 
            className={`flex flex-col md:flex-row gap-12 lg:gap-20 items-center mb-20 last:mb-0 ${
              section.reverse ? 'md:flex-row-reverse' : ''
            }`}
          >
            {/* Text Content */}
            <div className="flex-1">
              {section.heading && (
                <div className="mb-6">
                    <h2 className="text-3xl font-bold text-slate-900 mb-4">{section.heading}</h2>
                    <div className="w-16 h-1 bg-yellow-400 rounded-full"></div>
                </div>
              )}

              <div className="text-lg text-slate-600 leading-relaxed whitespace-pre-line">
                {section.content}
              </div>

              {section.list && (
                <ul className="mt-6 space-y-3">
                  {section.list.map((item, i) => (
                    <li key={i} className="flex items-start gap-3 text-slate-700">
                      <div className="mt-1.5 w-1.5 h-1.5 rounded-full bg-blue-500 shrink-0" />
                      <span>{item}</span>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            {/* Image Content */}
            {section.image && (
              <div className="flex-1 w-full">
                <div className="relative rounded-2xl overflow-hidden shadow-2xl group">
                    <div className="absolute inset-0 bg-blue-600/10 group-hover:bg-transparent transition-colors duration-500"></div>
                    <img 
                        src={section.image} 
                        alt={section.heading || "Section Image"} 
                        className="w-full h-auto object-cover transform group-hover:scale-105 transition-transform duration-700"
                    />
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* CTA at the bottom of generic pages */}
      <div className="bg-slate-50 py-16 border-t border-slate-100">
          <div className="max-w-4xl mx-auto px-4 text-center">
              <h2 className="text-2xl font-bold text-slate-900 mb-6">Ready to transform your business?</h2>
              <Link to="/contact" className="inline-flex items-center justify-center px-8 py-4 bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold rounded-full transition-all shadow-lg hover:shadow-xl hover:-translate-y-1">
                  Contact Us Today
                  <ArrowRight className="ml-2 w-5 h-5" />
