                <div className="absolute -right-[10%] bottom-[0%] w-[50%] h-[60%] bg-blue-100/30 rounded-full blur-3xl"></div>
            </div>

            <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
