import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Zap, Search, ChevronRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { MegaMenuConfig } from '../../../types';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') && 
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // Reset search when active submenu changes
  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  // Helper to filter items based on search query
  const getFilteredItems = (megaMenu: MegaMenuConfig, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col) => {
      if (col.items) {
        col.items.forEach((item) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group) => {
          group.items.forEach((item) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  const renderMegaMenu = (item: typeof NAV_ITEMS[0]) => {
    if (!item.megaMenu) return null;

    const { variant = 'compact', leftContent } = item.megaMenu;
    const isSidebarLayout = variant === 'sidebar-light' || variant === 'sidebar-dark';
    const isDarkSidebar = variant === 'sidebar-dark';

    return (
      <div className={`bg-white shadow-2xl rounded-2xl border border-slate-100 overflow-hidden mega-menu-container ${isSidebarLayout ? 'flex flex-row' : ''}`}>

        {/* Left Sidebar Layout */}
        {isSidebarLayout && leftContent && (
          <div className={`w-80 flex-shrink-0 p-8 flex flex-col justify-between border-r border-slate-100 ${isDarkSidebar ? 'bg-slate-900 text-white' : 'bg-slate-50 text-slate-900'}`}>
            <div>
              {leftContent.badgeText && (
                <span className={`inline-block px-2 py-1 text-[10px] font-bold rounded mb-4 w-fit ${isDarkSidebar ? 'bg-blue-600 text-white' : 'bg-yellow-400 text-slate-900'}`}>
                  {leftContent.badgeText}
                </span>
              )}
              <h3 className={`font-bold text-2xl mb-3 leading-tight ${isDarkSidebar ? 'text-white' : 'text-slate-900'}`}>
                {leftContent.title}
              </h3>
              <p className={`text-sm leading-relaxed mb-6 ${isDarkSidebar ? 'text-slate-400' : 'text-slate-600'}`}>
                {leftContent.description}
              </p>
              {leftContent.image && !isDarkSidebar && (
                <img 
                  src={leftContent.image} 
                  alt="Feature" 
                  className="w-full h-32 object-cover rounded-lg mix-blend-multiply mb-4"
                />
              )}
            </div>

            {/* Bottom Left Search Bar */}
            <div className="mt-8">
               <div className="relative">
                 <Search className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isDarkSidebar ? 'text-slate-500' : 'text-slate-400'}`} />
                 <input 
                   type="text"
                   placeholder={`Find in ${item.title}...`}
                   className={`w-full pl-9 pr-3 py-2.5 rounded-lg text-sm transition-all focus:outline-none focus:ring-2 ${
                     isDarkSidebar 
                       ? 'bg-slate-800 border-slate-700 text-white placeholder:text-slate-500 focus:ring-blue-500 focus:border-transparent'
                       : 'bg-white border-slate-200 text-slate-700 placeholder:text-slate-400 focus:ring-yellow-400 focus:border-yellow-400 shadow-sm'
                   }`}
                   value={menuSearchQuery}
                   onChange={(e) => setMenuSearchQuery(e.target.value)}
                   onClick={(e) => e.stopPropagation()}
                 />
               </div>
            </div>
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 min-w-[600px]">
          {/* Top Search for Non-Sidebar Layouts */}
          {!isSidebarLayout && (
             <div className="px-8 pt-6 pb-2 border-b border-slate-50">
                <div className="relative max-w-md">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                    <input 
                        type="text" 
                        placeholder={`Search ${item.title}...`}
                        className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 focus:border-yellow-400 transition-all text-sm font-medium text-slate-700 placeholder:text-slate-400"
                        value={menuSearchQuery}
                        onChange={(e) => setMenuSearchQuery(e.target.value)}
                        onClick={(e) => e.stopPropagation()}
                    />
                </div>
            </div>
          )}

          {/* Search Results Overlay */}
          {menuSearchQuery ? (
             <div className="p-8 min-h-[300px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
               {(() => {
                   const results = getFilteredItems(item.megaMenu!, menuSearchQuery);
                   return results.length > 0 ? (
                       <div>
                           <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Search Results ({results.length})</h4>
                           <div className="grid grid-cols-2 gap-4">
                               {results.map((res, idx) => (
                                   <Link 
                                       key={idx} 
                                       to={res.href}
                                       onClick={() => setActiveSubmenu(null)}
                                       className="flex flex-col p-4 rounded-xl bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 transition-all group"
                                   >
                                       <span className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors mb-1 text-sm flex items-center justify-between">
                                           {res.title}
                                           <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-opacity transform group-hover:translate-x-1" />
                                       </span>
                                       {res.context && <span className="text-xs text-slate-500">{res.context}</span>}
                                   </Link>
                               ))}
                           </div>
                       </div>
                   ) : (
                       <div className="flex flex-col items-center justify-center h-full py-12 text-slate-400">
                           <Search size={24} className="mb-2 opacity-50" />
                           <p className="font-medium text-slate-500">No matches found</p>
                       </div>
                   );
               })()}
             </div>
          ) : (
            /* Grid Content */
            <div className={`p-8 grid gap-8 ${variant === 'compact' ? 'grid-cols-2' : 'grid-cols-4'}`}>
              {item.megaMenu?.columns.map((column, idx) => (
                <div key={idx} className="space-y-6">
                  {column.groups ? (
                    column.groups.map((group, gIdx) => (
                      <div key={gIdx} className="space-y-4">
                        {group.title && (
                          <h4 className="text-[14px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block uppercase tracking-wider">
                            {group.title}
                          </h4>
                        )}
                        <ul className="space-y-2">
                          {group.items.map((subItem, sIdx) => (
                            <li key={sIdx}>
                              <Link
                                to={subItem.href}
                                onClick={() => setActiveSubmenu(null)}
                                className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit block py-0.5 hover:translate-x-1 transition-transform duration-200"
                              >
                                {subItem.title}
                              </Link>
                            </li>
                          ))}
                        </ul>
                      </div>
                    ))
                  ) : (
                    <div className="space-y-4">
                      {column.title ? (
                         <h4 className="text-[14px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block uppercase tracking-wider">
                           {column.title}
                         </h4>
                      ) : column.title === "" ? (
                         /* Spacer */
                         <div className="h-6"></div>
                      ) : null}

                      <ul className="space-y-2">
                        {column.items?.map((subItem, sIdx) => (
                          <li key={sIdx}>
                            <Link
                              to={subItem.href}
                              onClick={() => setActiveSubmenu(null)}
                              className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit block py-0.5 hover:translate-x-1 transition-transform duration-200"
                            >
                              {subItem.title}
                            </Link>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/95 backdrop-blur-md shadow-md py-3' : 'bg-white py-5'
        }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between">

          {/* Logo on Left */}
          <Link to="/" className="flex-shrink-0 flex items-center gap-2 cursor-pointer group">
            <img src="https://www.gnjworldwide.com/Logo.png" className="h-12 w-auto" alt="GnJ Worldwide Logo" />
            <span className="font-bold text-xl tracking-tight text-slate-900 group-hover:text-slate-700 transition-colors">
              GnJ<span className="text-yellow-500">Worldwide</span>
            </span>
          </Link>

          {/* Menu Items in Center */}
          <div className="hidden lg:flex items-center justify-center flex-1 mx-8">
            <div className="flex items-center gap-2">
              {NAV_ITEMS.map((item) => (
                <div
                  key={item.title}
                  className={item.megaMenu ? "static" : "relative"}
                >
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-[15px] font-medium transition-colors duration-200 ${activeSubmenu === item.title
                        ? 'text-slate-900 bg-slate-100'
                        : 'text-slate-600 hover:text-slate-900 hover:bg-slate-100'
                        }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1.5 w-4 h-4 transition-transform duration-200 ${activeSubmenu === item.title ? 'rotate-180 text-slate-900' : 'text-slate-400'
                          }`}
                      />
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-4 py-2 text-[15px] font-medium text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors"
                    >
                      {item.title}
                    </Link>
                  )}

                  {/* Mega Menu Dropdown */}
                  {item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 w-full pt-4 z-50 animate-slide-down">
                       {renderMegaMenu(item)}
                    </div>
                  )}

                  {/* Regular Dropdown (if any) */}
                  {item.children && !item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 py-2 z-50">
                      {item.children.map((subItem) => (
                        <Link
                          key={subItem.title}
                          to={subItem.href}
                          onClick={() => setActiveSubmenu(null)}
                          className="block px-4 py-2.5 text-sm text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors"
                        >
                          {subItem.title}
                        </Link>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right Side Actions */}
          <div className="hidden lg:flex items-center gap-3">
            <button
              className="p-2.5 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            <button className="relative overflow-hidden group bg-yellow-400 hover:bg-yellow-500 text-white font-bold p-3  transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-[0_8px_20px_-6px_rgba(250,204,21,0.6)] active:translate-y-0 active:shadow-none">
              <span className="relative z-10 flex items-center">
                Contact Us
              </span>
              <div className="absolute top-0 left-[-100%] w-[40%] h-full bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-[-20deg] group-hover:animate-shimmer"></div>
            </button>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2">
            <button
              className="p-2 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={22} />
            </button>

            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50 bg-white">
          <div className="flex flex-col h-full">
            <div className="flex items-center justify-between p-4 border-b border-gray-100">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-black text-white rounded-lg flex items-center justify-center">
                  <Zap size={18} fill="currentColor" />
                </div>
                <span className="font-bold text-lg text-slate-900">Nova<span className="text-yellow-500">Tech</span></span>
              </div>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"
              >
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto py-4 px-4 space-y-2">
              {NAV_ITEMS.map((item) => (
                <div key={item.title} className="border-b border-gray-50 last:border-0 pb-2">
                  <div
                    className="flex items-center justify-between w-full px-4 py-3 text-base font-semibold text-slate-800 rounded-xl hover:bg-slate-50 cursor-pointer active:bg-slate-100 transition-colors"
                    onClick={() => {
                      if (item.children || item.megaMenu) {
                        setActiveSubmenu(activeSubmenu === item.title ? null : item.title);
                      } else {
                        setIsMobileMenuOpen(false);
                      }
                    }}
                  >
                    {item.children || item.megaMenu ? (
                      <span>{item.title}</span>
                    ) : (
                      <Link to={item.href} onClick={() => setIsMobileMenuOpen(false)}>
                        {item.title}
                      </Link>
                    )}

                    {(item.children || item.megaMenu) && (
                      <ChevronDown
                        className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : ''}`}
                      />
                    )}
                  </div>

                  {activeSubmenu === item.title && (
                    <div className="pl-4 pr-2 py-2 space-y-1">
                      {item.megaMenu ? (
                        item.megaMenu.columns.map((col, idx) => (
                          <div key={idx} className="mb-4">
                            {col.groups ? (
                              col.groups.map((group, gIdx) => (
                                <div key={gIdx} className="mb-4">
                                  {group.title && (
                                    <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{group.title}</h5>
                                  )}
                                  {group.items.map(subItem => (
                                    <Link
                                      key={subItem.title}
                                      to={subItem.href}
                                      onClick={() => setIsMobileMenuOpen(false)}
                                      className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                    >
                                      {subItem.title}
                                    </Link>
                                  ))}
                                </div>
                              ))
                            ) : (
                              <>
                                {col.title && (
                                  <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{col.title}</h5>
                                )}
                                {col.items?.map(subItem => (
                                  <Link
                                    key={subItem.title}
                                    to={subItem.href}
                                    onClick={() => setIsMobileMenuOpen(false)}
                                    className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                  >
                                    {subItem.title}
                                  </Link>
                                ))}
                              </>
                            )}
                          </div>
                        ))
                      ) : (
                        item.children?.map((subItem) => (
                          <Link
                            key={subItem.title}
                            to={subItem.href}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="flex items-center p-3 text-sm font-medium text-slate-600 rounded-lg hover:bg-yellow-50 hover:text-slate-900 transition-colors"
                          >
                            {subItem.title}
                          </Link>
                        ))
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-4 border-t border-gray-100">
              <button className="w-full flex justify-center items-center bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold py-4 rounded-2xl transition-all shadow-lg active:scale-95">
                Contact Us <ArrowRight className="ml-2 w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Zap, Search, ChevronRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { MegaMenuConfig } from '../../../types';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') && 
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // Reset search when active submenu changes
  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  // Helper to filter items based on search query
  const getFilteredItems = (megaMenu: MegaMenuConfig, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col) => {
      if (col.items) {
        col.items.forEach((item) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group) => {
          group.items.forEach((item) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  const renderMegaMenu = (item: typeof NAV_ITEMS[0]) => {
    if (!item.megaMenu) return null;

    const { variant = 'compact', leftContent } = item.megaMenu;
    const isSidebarLayout = variant === 'sidebar-light' || variant === 'sidebar-dark';
    const isDarkSidebar = variant === 'sidebar-dark';

    return (
      <div className={`bg-white shadow-2xl rounded-2xl border border-slate-100 overflow-hidden mega-menu-container ${isSidebarLayout ? 'flex flex-row' : ''}`}>

        {/* Left Sidebar Layout */}
        {isSidebarLayout && leftContent && (
          <div className={`w-80 flex-shrink-0 p-8 flex flex-col justify-between border-r border-slate-100 opacity-0 animate-fade-in-up ${isDarkSidebar ? 'bg-slate-900 text-white' : 'bg-slate-50 text-slate-900'}`} style={{ animationDelay: '0ms' }}>
            <div>
              {leftContent.badgeText && (
                <span className={`inline-block px-2 py-1 text-[10px] font-bold rounded mb-4 w-fit ${isDarkSidebar ? 'bg-blue-600 text-white' : 'bg-yellow-400 text-slate-900'}`}>
                  {leftContent.badgeText}
                </span>
              )}
              <h3 className={`font-bold text-2xl mb-3 leading-tight ${isDarkSidebar ? 'text-white' : 'text-slate-900'}`}>
                {leftContent.title}
              </h3>
              <p className={`text-sm leading-relaxed mb-6 ${isDarkSidebar ? 'text-slate-400' : 'text-slate-600'}`}>
                {leftContent.description}
              </p>
              {leftContent.image && !isDarkSidebar && (
                <img 
                  src={leftContent.image} 
                  alt="Feature" 
                  className="w-full h-32 object-cover rounded-lg mix-blend-multiply mb-4"
                />
              )}
            </div>

            {/* Bottom Left Search Bar */}
            <div className="mt-8">
               <div className="relative">
                 <Search className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isDarkSidebar ? 'text-slate-500' : 'text-slate-400'}`} />
                 <input 
                   type="text"
                   placeholder={`Find in ${item.title}...`}
                   className={`w-full pl-9 pr-3 py-2.5 rounded-lg text-sm transition-all focus:outline-none focus:ring-2 ${
                     isDarkSidebar 
                       ? 'bg-slate-800 border-slate-700 text-white placeholder:text-slate-500 focus:ring-blue-500 focus:border-transparent'
                       : 'bg-white border-slate-200 text-slate-700 placeholder:text-slate-400 focus:ring-yellow-400 focus:border-yellow-400 shadow-sm'
                   }`}
                   value={menuSearchQuery}
                   onChange={(e) => setMenuSearchQuery(e.target.value)}
                   onClick={(e) => e.stopPropagation()}
                 />
               </div>
            </div>
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 min-w-[600px]">
          {/* Top Search for Non-Sidebar Layouts */}
          {!isSidebarLayout && (
             <div className="px-8 pt-6 pb-2 border-b border-slate-50 opacity-0 animate-fade-in-up" style={{ animationDelay: '100ms' }}>
                <div className="relative max-w-md">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                    <input 
                        type="text" 
                        placeholder={`Search ${item.title}...`}
                        className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 focus:border-yellow-400 transition-all text-sm font-medium text-slate-700 placeholder:text-slate-400"
                        value={menuSearchQuery}
                        onChange={(e) => setMenuSearchQuery(e.target.value)}
                        onClick={(e) => e.stopPropagation()}
                    />
                </div>
            </div>
          )}

          {/* Search Results Overlay */}
          {menuSearchQuery ? (
             <div className="p-8 min-h-[300px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
               {(() => {
                   const results = getFilteredItems(item.megaMenu!, menuSearchQuery);
                   return results.length > 0 ? (
                       <div className="opacity-0 animate-fade-in-up">
                           <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Search Results ({results.length})</h4>
                           <div className="grid grid-cols-2 gap-4">
                               {results.map((res, idx) => (
                                   <Link 
                                       key={idx} 
                                       to={res.href}
                                       onClick={() => setActiveSubmenu(null)}
                                       className="flex flex-col p-4 rounded-xl bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 transition-all group opacity-0 animate-fade-in-up"
                                       style={{ animationDelay: `${idx * 50}ms` }}
                                   >
                                       <span className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors mb-1 text-sm flex items-center justify-between">
                                           {res.title}
                                           <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-opacity transform group-hover:translate-x-1" />
                                       </span>
                                       {res.context && <span className="text-xs text-slate-500">{res.context}</span>}
                                   </Link>
                               ))}
                           </div>
                       </div>
                   ) : (
                       <div className="flex flex-col items-center justify-center h-full py-12 text-slate-400 opacity-0 animate-fade-in-up">
                           <Search size={24} className="mb-2 opacity-50" />
                           <p className="font-medium text-slate-500">No matches found</p>
                       </div>
                   );
               })()}
             </div>
          ) : (
            /* Grid Content */
            <div className={`p-8 grid gap-8 ${variant === 'compact' ? 'grid-cols-2' : 'grid-cols-4'}`}>
              {item.megaMenu?.columns.map((column, idx) => (
                <div key={idx} className="space-y-6 opacity-0 animate-fade-in-up" style={{ animationDelay: `${(idx + 1) * 75}ms` }}>
                  {column.groups ? (
                    column.groups.map((group, gIdx) => (
                      <div key={gIdx} className="space-y-4">
                        {group.title && (
                          <h4 className="text-[14px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block uppercase tracking-wider">
                            {group.title}
                          </h4>
                        )}
                        <ul className="space-y-2">
                          {group.items.map((subItem, sIdx) => (
                            <li key={sIdx}>
                              <Link
                                to={subItem.href}
                                onClick={() => setActiveSubmenu(null)}
                                className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit block py-0.5 hover:translate-x-1 transition-transform duration-200"
                              >
                                {subItem.title}
                              </Link>
                            </li>
                          ))}
                        </ul>
                      </div>
                    ))
                  ) : (
                    <div className="space-y-4">
                      {column.title ? (
                         <h4 className="text-[14px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block uppercase tracking-wider">
                           {column.title}
                         </h4>
                      ) : column.title === "" ? (
                         /* Spacer */
                         <div className="h-6"></div>
                      ) : null}

                      <ul className="space-y-2">
                        {column.items?.map((subItem, sIdx) => (
                          <li key={sIdx}>
                            <Link
                              to={subItem.href}
                              onClick={() => setActiveSubmenu(null)}
                              className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit block py-0.5 hover:translate-x-1 transition-transform duration-200"
                            >
                              {subItem.title}
                            </Link>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/95 backdrop-blur-md shadow-md py-3' : 'bg-white py-5'
        }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between">

          {/* Logo on Left */}
          <Link to="/" className="flex-shrink-0 flex items-center gap-2 cursor-pointer group">
            <img src="https://www.gnjworldwide.com/Logo.png" className="h-12 w-auto" alt="GnJ Worldwide Logo" />
            <span className="font-bold text-xl tracking-tight text-slate-900 group-hover:text-slate-700 transition-colors">
              GnJ<span className="text-yellow-500">Worldwide</span>
            </span>
          </Link>

          {/* Menu Items in Center */}
          <div className="hidden lg:flex items-center justify-center flex-1 mx-8">
            <div className="flex items-center gap-2">
              {NAV_ITEMS.map((item) => (
                <div
                  key={item.title}
                  className={item.megaMenu ? "static" : "relative"}
                >
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-[15px] font-medium transition-colors duration-200 ${activeSubmenu === item.title
                        ? 'text-slate-900 bg-slate-100'
                        : 'text-slate-600 hover:text-slate-900 hover:bg-slate-100'
                        }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1.5 w-4 h-4 transition-transform duration-200 ${activeSubmenu === item.title ? 'rotate-180 text-slate-900' : 'text-slate-400'
                          }`}
                      />
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-4 py-2 text-[15px] font-medium text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors"
                    >
                      {item.title}
                    </Link>
                  )}

                  {/* Mega Menu Dropdown */}
                  {item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 w-full pt-4 z-50 animate-slide-down">
                       {renderMegaMenu(item)}
                    </div>
                  )}

                  {/* Regular Dropdown (if any) */}
                  {item.children && !item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 py-2 z-50">
                      {item.children.map((subItem) => (
                        <Link
                          key={subItem.title}
                          to={subItem.href}
                          onClick={() => setActiveSubmenu(null)}
                          className="block px-4 py-2.5 text-sm text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors"
                        >
                          {subItem.title}
                        </Link>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right Side Actions */}
          <div className="hidden lg:flex items-center gap-3">
            <button
              className="p-2.5 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            <button className="relative overflow-hidden group bg-yellow-400 hover:bg-yellow-500 text-white font-bold p-3  transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-[0_8px_20px_-6px_rgba(250,204,21,0.6)] active:translate-y-0 active:shadow-none">
              <span className="relative z-10 flex items-center">
                Contact Us
              </span>
              <div className="absolute top-0 left-[-100%] w-[40%] h-full bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-[-20deg] group-hover:animate-shimmer"></div>
            </button>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2">
            <button
              className="p-2 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={22} />
            </button>

            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50 bg-white">
          <div className="flex flex-col h-full">
            <div className="flex items-center justify-between p-4 border-b border-gray-100">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-black text-white rounded-lg flex items-center justify-center">
                  <Zap size={18} fill="currentColor" />
                </div>
                <span className="font-bold text-lg text-slate-900">Nova<span className="text-yellow-500">Tech</span></span>
              </div>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"
              >
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto py-4 px-4 space-y-2">
              {NAV_ITEMS.map((item) => (
                <div key={item.title} className="border-b border-gray-50 last:border-0 pb-2">
                  <div
                    className="flex items-center justify-between w-full px-4 py-3 text-base font-semibold text-slate-800 rounded-xl hover:bg-slate-50 cursor-pointer active:bg-slate-100 transition-colors"
                    onClick={() => {
                      if (item.children || item.megaMenu) {
                        setActiveSubmenu(activeSubmenu === item.title ? null : item.title);
                      } else {
                        setIsMobileMenuOpen(false);
                      }
                    }}
                  >
                    {item.children || item.megaMenu ? (
                      <span>{item.title}</span>
                    ) : (
                      <Link to={item.href} onClick={() => setIsMobileMenuOpen(false)}>
                        {item.title}
                      </Link>
                    )}

                    {(item.children || item.megaMenu) && (
                      <ChevronDown
                        className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : ''}`}
                      />
                    )}
                  </div>

                  {/* Mobile Submenu Rendering */}
                  {activeSubmenu === item.title && (
                    <div className="pl-4 pr-2 py-2 space-y-1">
                      {/* Handle Mega Menu Items for Mobile */}
                      {item.megaMenu ? (
                        item.megaMenu.columns.map((col, idx) => (
                          <div key={idx} className="mb-4">
                            {/* Handle Grouped Columns in Mobile */}
                            {col.groups ? (
                              col.groups.map((group, gIdx) => (
                                <div key={gIdx} className="mb-4">
                                  {group.title && (
                                    <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{group.title}</h5>
                                  )}
                                  {group.items.map(subItem => (
                                    <Link
                                      key={subItem.title}
                                      to={subItem.href}
                                      onClick={() => setIsMobileMenuOpen(false)}
                                      className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                    >
                                      {subItem.title}
                                    </Link>
                                  ))}
                                </div>
                              ))
                            ) : (
                              <>
                                {col.title && (
                                  <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{col.title}</h5>
                                )}
                                {col.items?.map(subItem => (
                                  <Link
                                    key={subItem.title}
                                    to={subItem.href}
                                    onClick={() => setIsMobileMenuOpen(false)}
                                    className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                  >
                                    {subItem.title}
                                  </Link>
                                ))}
                              </>
                            )}
                          </div>
                        ))
                      ) : (
                        item.children?.map((subItem) => (
                          <Link
                            key={subItem.title}
                            to={subItem.href}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="flex items-center p-3 text-sm font-medium text-slate-600 rounded-lg hover:bg-yellow-50 hover:text-slate-900 transition-colors"
                          >
                            {subItem.title}
                          </Link>
                        ))
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-4 border-t border-gray-100">
              <button className="w-full flex justify-center items-center bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold py-4 rounded-2xl transition-all shadow-lg active:scale-95">
                Contact Us <ArrowRight className="ml-2 w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import { LucideIcon } from 'lucide-react';

export interface SubMenuItem {
  title: string;
  description?: string;
  href: string;
  icon?: LucideIcon;
}

export interface MegaMenuLink {
  title: string;
  href: string;
}

export interface MegaMenuGroup {
  title: string;
  items: MegaMenuLink[];
}

export interface MegaMenuColumn {
  title?: string;
  items?: MegaMenuLink[];
  groups?: MegaMenuGroup[];
}

export interface MegaMenuConfig {
  variant?: 'compact' | 'sidebar-light' | 'sidebar-dark';
  leftContent?: {
    title: string;
    description: string;
    image?: string;
    badgeText?: string;
  };
  columns: MegaMenuColumn[];
}

export interface MenuItem {
  title: string;
  href: string;
  children?: SubMenuItem[];
  megaMenu?: MegaMenuConfig;
  featured?: {
    title: string;
    description: string;
    image: string;
    href: string;
  };
}

import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Zap, Search, ChevronRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { MegaMenuConfig } from '../../../types';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') && 
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // Reset search when active submenu changes
  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  // Helper to filter items based on search query
  const getFilteredItems = (megaMenu: MegaMenuConfig, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col) => {
      if (col.items) {
        col.items.forEach((item) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group) => {
          group.items.forEach((item) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  const renderMegaMenu = (item: typeof NAV_ITEMS[0]) => {
    if (!item.megaMenu) return null;

    const { leftContent } = item.megaMenu;
    // Default to 'sidebar-light' if leftContent exists but variant is not specified, otherwise 'compact'
    const variant = item.megaMenu.variant || (leftContent ? 'sidebar-light' : 'compact');

    const isSidebarLayout = variant === 'sidebar-light' || variant === 'sidebar-dark';
    const isDarkSidebar = variant === 'sidebar-dark';

    return (
      <div className={`bg-white shadow-2xl rounded-2xl border border-slate-100 overflow-hidden mega-menu-container ${isSidebarLayout ? 'flex flex-row' : ''}`}>

        {/* Left Sidebar Layout */}
        {isSidebarLayout && leftContent && (
          <div className={`w-80 flex-shrink-0 p-8 flex flex-col justify-between border-r border-slate-100 opacity-0 animate-fade-in-up ${isDarkSidebar ? 'bg-slate-900 text-white' : 'bg-slate-50 text-slate-900'}`} style={{ animationDelay: '0ms' }}>
            <div>
              {leftContent.badgeText && (
                <span className={`inline-block px-2 py-1 text-[10px] font-bold rounded mb-4 w-fit ${isDarkSidebar ? 'bg-blue-600 text-white' : 'bg-yellow-400 text-slate-900'}`}>
                  {leftContent.badgeText}
                </span>
              )}
              <h3 className={`font-bold text-2xl mb-3 leading-tight ${isDarkSidebar ? 'text-white' : 'text-slate-900'}`}>
                {leftContent.title}
              </h3>
              <p className={`text-sm leading-relaxed mb-6 ${isDarkSidebar ? 'text-slate-400' : 'text-slate-600'}`}>
                {leftContent.description}
              </p>
              {leftContent.image && !isDarkSidebar && (
                <img 
                  src={leftContent.image} 
                  alt="Feature" 
                  className="w-full h-32 object-cover rounded-lg mix-blend-multiply mb-4"
                />
              )}
            </div>

            {/* Bottom Left Search Bar */}
            <div className="mt-8">
               <div className="relative">
                 <Search className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isDarkSidebar ? 'text-slate-500' : 'text-slate-400'}`} />
                 <input 
                   type="text"
                   placeholder={`Find in ${item.title}...`}
                   className={`w-full pl-9 pr-3 py-2.5 rounded-lg text-sm transition-all focus:outline-none focus:ring-2 ${
                     isDarkSidebar 
                       ? 'bg-slate-800 border-slate-700 text-white placeholder:text-slate-500 focus:ring-blue-500 focus:border-transparent'
                       : 'bg-white border-slate-200 text-slate-700 placeholder:text-slate-400 focus:ring-yellow-400 focus:border-yellow-400 shadow-sm'
                   }`}
                   value={menuSearchQuery}
                   onChange={(e) => setMenuSearchQuery(e.target.value)}
                   onClick={(e) => e.stopPropagation()}
                 />
               </div>
            </div>
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 min-w-[600px]">
          {/* Top Search for Non-Sidebar Layouts */}
          {!isSidebarLayout && (
             <div className="px-8 pt-6 pb-2 border-b border-slate-50 opacity-0 animate-fade-in-up" style={{ animationDelay: '100ms' }}>
                <div className="relative max-w-md">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                    <input 
                        type="text" 
                        placeholder={`Search ${item.title}...`}
                        className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 focus:border-yellow-400 transition-all text-sm font-medium text-slate-700 placeholder:text-slate-400"
                        value={menuSearchQuery}
                        onChange={(e) => setMenuSearchQuery(e.target.value)}
                        onClick={(e) => e.stopPropagation()}
                    />
                </div>
            </div>
          )}

          {/* Search Results Overlay */}
          {menuSearchQuery ? (
             <div className="p-8 min-h-[300px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
               {(() => {
                   const results = getFilteredItems(item.megaMenu!, menuSearchQuery);
                   return results.length > 0 ? (
                       <div className="opacity-0 animate-fade-in-up">
                           <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Search Results ({results.length})</h4>
                           <div className="grid grid-cols-2 gap-4">
                               {results.map((res, idx) => (
                                   <Link 
                                       key={idx} 
                                       to={res.href}
                                       onClick={() => setActiveSubmenu(null)}
                                       className="flex flex-col p-4 rounded-xl bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 transition-all group opacity-0 animate-fade-in-up"
                                       style={{ animationDelay: `${idx * 50}ms` }}
                                   >
                                       <span className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors mb-1 text-sm flex items-center justify-between">
                                           {res.title}
                                           <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-opacity transform group-hover:translate-x-1" />
                                       </span>
                                       {res.context && <span className="text-xs text-slate-500">{res.context}</span>}
                                   </Link>
                               ))}
                           </div>
                       </div>
                   ) : (
                       <div className="flex flex-col items-center justify-center h-full py-12 text-slate-400 opacity-0 animate-fade-in-up">
                           <Search size={24} className="mb-2 opacity-50" />
                           <p className="font-medium text-slate-500">No matches found</p>
                       </div>
                   );
               })()}
             </div>
          ) : (
            /* Grid Content */
            <div className={`p-8 grid gap-8 ${variant === 'compact' ? 'grid-cols-2' : 'grid-cols-4'}`}>
              {item.megaMenu?.columns.map((column, idx) => (
                <div key={idx} className="space-y-6 opacity-0 animate-fade-in-up" style={{ animationDelay: `${(idx + 1) * 75}ms` }}>
                  {column.groups ? (
                    column.groups.map((group, gIdx) => (
                      <div key={gIdx} className="space-y-4">
                        {group.title && (
                          <h4 className="text-[14px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block uppercase tracking-wider">
                            {group.title}
                          </h4>
                        )}
                        <ul className="space-y-2">
                          {group.items.map((subItem, sIdx) => (
                            <li key={sIdx}>
                              <Link
                                to={subItem.href}
                                onClick={() => setActiveSubmenu(null)}
                                className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit block py-0.5 hover:translate-x-1 transition-transform duration-200"
                              >
                                {subItem.title}
                              </Link>
                            </li>
                          ))}
                        </ul>
                      </div>
                    ))
                  ) : (
                    <div className="space-y-4">
                      {column.title ? (
                         <h4 className="text-[14px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block uppercase tracking-wider">
                           {column.title}
                         </h4>
                      ) : column.title === "" ? (
                         /* Spacer */
                         <div className="h-6"></div>
                      ) : null}

                      <ul className="space-y-2">
                        {column.items?.map((subItem, sIdx) => (
                          <li key={sIdx}>
                            <Link
                              to={subItem.href}
                              onClick={() => setActiveSubmenu(null)}
                              className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit block py-0.5 hover:translate-x-1 transition-transform duration-200"
                            >
                              {subItem.title}
                            </Link>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/95 backdrop-blur-md shadow-md py-3' : 'bg-white py-5'
        }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between">

          {/* Logo on Left */}
          <Link to="/" className="flex-shrink-0 flex items-center gap-2 cursor-pointer group">
            <img src="https://www.gnjworldwide.com/Logo.png" className="h-12 w-auto" alt="GnJ Worldwide Logo" />
            <span className="font-bold text-xl tracking-tight text-slate-900 group-hover:text-slate-700 transition-colors">
              GnJ<span className="text-yellow-500">Worldwide</span>
            </span>
          </Link>

          {/* Menu Items in Center */}
          <div className="hidden lg:flex items-center justify-center flex-1 mx-8">
            <div className="flex items-center gap-2">
              {NAV_ITEMS.map((item) => (
                <div
                  key={item.title}
                  className={item.megaMenu ? "static" : "relative"}
                >
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-[15px] font-medium transition-colors duration-200 ${activeSubmenu === item.title
                        ? 'text-slate-900 bg-slate-100'
                        : 'text-slate-600 hover:text-slate-900 hover:bg-slate-100'
                        }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1.5 w-4 h-4 transition-transform duration-200 ${activeSubmenu === item.title ? 'rotate-180 text-slate-900' : 'text-slate-400'
                          }`}
                      />
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-4 py-2 text-[15px] font-medium text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors"
                    >
                      {item.title}
                    </Link>
                  )}

                  {/* Mega Menu Dropdown */}
                  {item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 w-full pt-4 z-50 animate-slide-down">
                       {renderMegaMenu(item)}
                    </div>
                  )}

                  {/* Regular Dropdown (if any) */}
                  {item.children && !item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 py-2 z-50">
                      {item.children.map((subItem) => (
                        <Link
                          key={subItem.title}
                          to={subItem.href}
                          onClick={() => setActiveSubmenu(null)}
                          className="block px-4 py-2.5 text-sm text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors"
                        >
                          {subItem.title}
                        </Link>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right Side Actions */}
          <div className="hidden lg:flex items-center gap-3">
            <button
              className="p-2.5 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            <button className="relative overflow-hidden group bg-yellow-400 hover:bg-yellow-500 text-white font-bold p-3  transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-[0_8px_20px_-6px_rgba(250,204,21,0.6)] active:translate-y-0 active:shadow-none">
              <span className="relative z-10 flex items-center">
                Contact Us
              </span>
              <div className="absolute top-0 left-[-100%] w-[40%] h-full bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-[-20deg] group-hover:animate-shimmer"></div>
            </button>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2">
            <button
              className="p-2 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={22} />
            </button>

            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50 bg-white">
          <div className="flex flex-col h-full">
            <div className="flex items-center justify-between p-4 border-b border-gray-100">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-black text-white rounded-lg flex items-center justify-center">
                  <Zap size={18} fill="currentColor" />
                </div>
                <span className="font-bold text-lg text-slate-900">Nova<span className="text-yellow-500">Tech</span></span>
              </div>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"
              >
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto py-4 px-4 space-y-2">
              {NAV_ITEMS.map((item) => (
                <div key={item.title} className="border-b border-gray-50 last:border-0 pb-2">
                  <div
                    className="flex items-center justify-between w-full px-4 py-3 text-base font-semibold text-slate-800 rounded-xl hover:bg-slate-50 cursor-pointer active:bg-slate-100 transition-colors"
                    onClick={() => {
                      if (item.children || item.megaMenu) {
                        setActiveSubmenu(activeSubmenu === item.title ? null : item.title);
                      } else {
                        setIsMobileMenuOpen(false);
                      }
                    }}
                  >
                    {item.children || item.megaMenu ? (
                      <span>{item.title}</span>
                    ) : (
                      <Link to={item.href} onClick={() => setIsMobileMenuOpen(false)}>
                        {item.title}
                      </Link>
                    )}

                    {(item.children || item.megaMenu) && (
                      <ChevronDown
                        className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : ''}`}
                      />
                    )}
                  </div>

                  {/* Mobile Submenu Rendering */}
                  {activeSubmenu === item.title && (
                    <div className="pl-4 pr-2 py-2 space-y-1">
                      {/* Handle Mega Menu Items for Mobile */}
                      {item.megaMenu ? (
                        item.megaMenu.columns.map((col, idx) => (
                          <div key={idx} className="mb-4">
                            {/* Handle Grouped Columns in Mobile */}
                            {col.groups ? (
                              col.groups.map((group, gIdx) => (
                                <div key={gIdx} className="mb-4">
                                  {group.title && (
                                    <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{group.title}</h5>
                                  )}
                                  {group.items.map(subItem => (
                                    <Link
                                      key={subItem.title}
                                      to={subItem.href}
                                      onClick={() => setIsMobileMenuOpen(false)}
                                      className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                    >
                                      {subItem.title}
                                    </Link>
                                  ))}
                                </div>
                              ))
                            ) : (
                              <>
                                {col.title && (
                                  <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{col.title}</h5>
                                )}
                                {col.items?.map(subItem => (
                                  <Link
                                    key={subItem.title}
                                    to={subItem.href}
                                    onClick={() => setIsMobileMenuOpen(false)}
                                    className="block py-2 text-sm font-medium text-slate-600 hover:text-slate-900"
                                  >
                                    {subItem.title}
                                  </Link>
                                ))}
                              </>
                            )}
                          </div>
                        ))
                      ) : (
                        item.children?.map((subItem) => (
                          <Link
                            key={subItem.title}
                            to={subItem.href}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="flex items-center p-3 text-sm font-medium text-slate-600 rounded-lg hover:bg-yellow-50 hover:text-slate-900 transition-colors"
                          >
                            {subItem.title}
                          </Link>
                        ))
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-4 border-t border-gray-100">
              <button className="w-full flex justify-center items-center bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold py-4 rounded-2xl transition-all shadow-lg active:scale-95">
                Contact Us <ArrowRight className="ml-2 w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useEffect, useRef, useState } from 'react';
import { useLocation, Link } from 'react-router-dom';
import { PAGE_DATA } from '../../data/ContentData';
