// --- Scroll Animation Component ---
const ScrollReveal: React.FC<{ 
  children: React.ReactNode; 
  className?: string; 
  delay?: number;
  threshold?: number;
}> = ({ 
  children, 
  className = "", 
  delay = 0,
  threshold = 0.1
}) => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { threshold, rootMargin: "0px 0px -50px 0px" }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => {
      observer.disconnect();
    };
  }, [threshold]);

  return (
    <div
      ref={ref}
      style={{ transitionDelay: `${delay}ms` }}
      className={`transition-all duration-1000 cubic-bezier(0.16, 1, 0.3, 1) transform ${
        isVisible ? "opacity-100 translate-y-0 scale-100" : "opacity-0 translate-y-12 scale-[0.98]"
      } ${className}`}
    >
      {children}
    </div>
  );
};

// --- Animated Text Component ---
const AnimatedTitle: React.FC<{ text: string; className?: string }> = ({ text, className = "" }) => {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  return (
    <h1 className={`${className} flex flex-wrap justify-center gap-x-3 gap-y-1`}>
      {text.split(" ").map((word, i) => (
        <span 
          key={i} 
          className={`inline-block transition-all duration-700 ease-out transform ${mounted ? 'opacity-100 translate-y-0 rotate-0' : 'opacity-0 translate-y-12 rotate-3'}`}
          style={{ transitionDelay: `${100 + i * 80}ms` }}
        >
          {word}
        </span>
      ))}
    </h1>
  );
};

