                                        <ul className="space-y-2.5">
                                          {group.items.map((subItem, sIdx) => (
                                            <li key={sIdx}>
                                              <Link
                                                to={subItem.href}
                                                onClick={() => setActiveSubmenu(null)}
                                                className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit after:absolute after:left-0 after:-bottom-1 after:h-[2px] after:w-full after:origin-left after:scale-x-0 after:bg-yellow-500 after:transition-transform after:duration-300 hover:after:scale-x-100 block"
                                              >
