                  {/* Regular Dropdown (Services/Simple) */}
                  {item.children && !item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 py-2 z-50">
