// --- Custom Router Implementation ---

const RouterContext = createContext<{ path: string }>({ path: '/' });

export const HashRouter: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [path, setPath] = useState(window.location.hash.slice(1) || '/');

  useEffect(() => {
    const handleHashChange = () => {
        let currentPath = window.location.hash.slice(1);
        if (!currentPath) currentPath = '/';
        setPath(currentPath);
    };

    if (!window.location.hash) {
        window.location.hash = '#/';
    } else {
        // Ensure path state syncs with initial hash
        handleHashChange();
    }

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  return React.createElement(RouterContext.Provider, { value: { path } }, children);
};

export const useLocation = () => {
   const context = useContext(RouterContext);
   return { pathname: context.path };
};

export interface LinkProps extends React.AnchorHTMLAttributes<HTMLAnchorElement> {
    to: string;
}

export const Link: React.FC<LinkProps> = ({ to, children, className, onClick, ...props }) => {
    const href = to.startsWith('/') ? `#${to}` : `#/${to}`;
    return React.createElement('a', {
        href,
        className,
        onClick,
        ...props
    }, children);
};

