  // Route matching logic
  let component = <HomePage />;

  switch (pathname) {
    case '/':
      component = <HomePage />;
      break;
    case '/contact':
      component = <div className="pt-20"><Contact /></div>;
      break;
    case '/about':
      component = <AboutPage />;
      break;
    case '/services':
      component = <ServicesPage />;
      break;
    case '/industries':
      component = <IndustriesPage />;
      break;
    case '/solutions':
      component = <SolutionsPage />;
      break;
    case '/technologies':
      component = <TechnologiesPage />;
      break;

    // Services - Software
    case '/services/software-development': component = <SoftwareDevelopmentPage />; break;
    case '/services/web-development': component = <WebDevelopmentPage />; break;
    case '/services/mobile-development': component = <MobileDevelopmentPage />; break;
    case '/services/desktop-development': component = <DesktopDevelopmentPage />; break;
    case '/services/api-development': component = <ApiDevelopmentPage />; break;
    case '/services/database-development': component = <DatabaseDevelopmentPage />; break;
    case '/services/software-modernization': component = <SoftwareModernizationPage />; break;

    // Services - Strategy & Advisory
    case '/services/it-consulting': component = <ItConsultingPage />; break;
    case '/services/digital-transformation': component = <DigitalTransformationPage />; break;
    case '/services/software-consulting': component = <SoftwareConsultingPage />; break;
    case '/services/it-project-management': component = <ItProjectManagementPage />; break;
    case '/services/agile-consulting': component = <GoogleConsultingPage />; break;
    case '/services/google-consulting': component = <GoogleConsultingPage />; break;
    case '/services/devops-consulting': component = <DevOpsConsultingPage />; break;
    case '/services/microsoft-consulting': component = <MicrosoftConsultingPage />; break;
    case '/services/servicenow-consulting': component = <ServiceNowConsultingPage />; break;
    case '/services/zoho-consulting': component = <ZohoConsultingPage />; break;

    // Services - Data & Intelligence
    case '/services/data-analytics': component = <DataAnalyticsPage />; break;
    case '/services/data-warehousing': component = <DataWarehousingPage />; break;
    case '/services/business-intelligence': component = <BusinessIntelligencePage />; break;
    case '/services/data-science': component = <DataSciencePage />; break;
    case '/services/machine-learning': component = <MachineLearningPage />; break;
    case '/services/artificial-intelligence': component = <ArtificialIntelligencePage />; break;

    // Services - Operations & Support
    case '/services/it-outsourcing': component = <ItOutsourcingPage />; break;
    case '/services/managed-it-services': component = <ManagedItServicesPage />; break;
    case '/services/infrastructure-services': component = <InfrastructureServicesPage />; break;
    case '/services/it-support': component = <ItSupportPage />; break;
    case '/services/it-help-desk': component = <ItHelpDeskPage />; break;
    case '/services/application-services': component = <ApplicationServicesPage />; break;
    case '/services/application-maintenance': component = <ApplicationMaintenancePage />; break;
    case '/services/testing-and-qa': component = <TestingAndQaPage />; break;

    // Services - Security
    case '/services/cybersecurity': component = <CybersecurityPage />; break;
    case '/services/compliance-services': component = <ComplianceServicesPage />; break;
    case '/services/security-testing': component = <SecurityTestingPage />; break;
    case '/services/penetration-testing': component = <PenetrationTestingPage />; break;
    case '/services/siem-services': component = <SiemServicesPage />; break;

    // Industries - Healthcare
    case '/industries/healthcare-it': component = <HealthcareItPage />; break;
    case '/industries/hospitals': component = <HospitalsPage />; break;
    case '/industries/medical-devices': component = <MedicalDevicesPage />; break;
    case '/industries/mental-health': component = <MentalHealthPage />; break;
    case '/industries/home-healthcare': component = <HomeHealthcarePage />; break;
    case '/industries/medical-labs': component = <MedicalLabsPage />; break;
    case '/industries/cro': component = <CroPage />; break;
    case '/industries/biotech-pharma': component = <BiotechPharmaPage />; break;
    case '/industries/payers': component = <PayersPage />; break;
    case '/industries/healthcare-software': component = <HealthcareSoftwarePage />; break;
    case '/industries/digital-health': component = <DigitalHealthPage />; break;
    case '/industries/public-health': component = <PublicHealthPage />; break;
    case '/industries/fitness-wellness': component = <FitnessWellnessPage />; break;

    // About
    case '/about/mission': component = <MissionPage />; break;
    case '/about/leadership': component = <LeadershipPage />; break;
    case '/about/team': component = <TeamPage />; break;
    case '/portfolio': component = <PortfolioPage />; break;
    case '/reviews': component = <ReviewsPage />; break;
    case '/partners': component = <PartnersPage />; break;
    case '/locations': component = <LocationsPage />; break;
    case '/careers': component = <CareersPage />; break;
    case '/careers/hiring': component = <HiringPage />; break;

    default:
      component = <HomePage />; // Default to Home or 404
      break;
  }

  return (
    <Layout>
      {component}
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <AppContent />
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Zap, Search, ChevronRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { motion, AnimatePresence } from 'framer-motion';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // If the click is not on a dropdown button AND not inside the menu container, close menus
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') && 
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // Reset search when active submenu changes
  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    // Prevent the document click listener from firing immediately
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  // Helper to filter items based on search query
  const getFilteredItems = (megaMenu: any, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col: any) => {
      if (col.items) {
        col.items.forEach((item: any) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group: any) => {
          group.items.forEach((item: any) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/95 backdrop-blur-md shadow-md py-3' : 'bg-white py-5'
        }`}
    >
      {/* Added 'relative' to the container to position absolute mega-menus correctly */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between">

          {/* Logo on Left */}
          <Link to="/" className="flex-shrink-0 flex items-center gap-2 cursor-pointer group">
            <img src="https://www.gnjworldwide.com/Logo.png" className="h-12 w-auto" alt="GnJ Worldwide Logo" />
            <span className="font-bold text-xl tracking-tight text-slate-900 group-hover:text-slate-700 transition-colors">
              GnJ<span className="text-yellow-500">Worldwide</span>
            </span>
          </Link>

          {/* Menu Items in Center */}
          <div className="hidden lg:flex items-center justify-center flex-1 mx-8">
            <div className="flex items-center gap-2">
              {NAV_ITEMS.map((item) => (
                <div
                  key={item.title}
                  // Use 'static' for megaMenu items so they position relative to the main container
                  // Use 'relative' for regular dropdowns so they position relative to the item
                  className={item.megaMenu ? "static" : "relative"}
                >
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-[15px] font-medium transition-colors duration-200 outline-none ${activeSubmenu === item.title
                        ? 'text-slate-900 bg-slate-100 rounded-lg'
                        : 'text-slate-600 hover:text-slate-900 hover:bg-slate-50 rounded-lg'
                        }`}
                    >
                      {item.title}
                      <motion.div
                        animate={{ rotate: activeSubmenu === item.title ? 180 : 0 }}
                        transition={{ duration: 0.2 }}
                        className="ml-1.5"
                      >
                        <ChevronDown className="w-4 h-4 text-slate-400" />
                      </motion.div>
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-4 py-2 text-[15px] font-medium text-slate-600 hover:text-slate-900 hover:bg-slate-50 rounded-lg transition-colors"
                    >
                      {item.title}
                    </Link>
                  )}

                  {/* Mega Menu Dropdown */}
                  <AnimatePresence>
                    {item.megaMenu && activeSubmenu === item.title && (
                      <motion.div
                        initial={{ opacity: 0, y: 15 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: 15 }}
                        transition={{ duration: 0.2, ease: "easeOut" }}
                        className="absolute top-full left-0 w-full pt-4 z-50"
                      >
                        <div className="bg-white shadow-2xl rounded-2xl border border-slate-100 overflow-hidden mega-menu-container">

                          {/* Search Bar Area */}
                          <div className="px-8 pt-8 pb-2">
                              <div className="relative">
                                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                                  <input 
                                      type="text" 
                                      placeholder={`Find in ${item.title}...`}
                                      className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 focus:border-yellow-400 transition-all text-sm font-medium text-slate-700 placeholder:text-slate-400"
                                      value={menuSearchQuery}
                                      onChange={(e) => setMenuSearchQuery(e.target.value)}
                                      autoFocus
                                      onClick={(e) => e.stopPropagation()}
                                  />
                              </div>
                          </div>

                          {menuSearchQuery ? (
                            // Search Results View
                            <div className="p-8 min-h-[250px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
                              {(() => {
                                  const results = getFilteredItems(item.megaMenu, menuSearchQuery);
                                  return results.length > 0 ? (
                                      <div>
                                          <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Search Results ({results.length})</h4>
                                          <div className="grid grid-cols-3 gap-4">
                                              {results.map((res, idx) => (
                                                  <Link 
                                                      key={idx} 
                                                      to={res.href}
                                                      onClick={() => setActiveSubmenu(null)}
                                                      className="flex flex-col p-4 rounded-xl bg-slate-50 hover:bg-white hover:shadow-md border border-transparent hover:border-slate-100 transition-all group"
                                                  >
                                                      <span className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors mb-1 text-sm flex items-center justify-between">
                                                          {res.title}
                                                          <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-opacity transform group-hover:translate-x-1" />
                                                      </span>
                                                      {res.context && <span className="text-xs text-slate-500">{res.context}</span>}
                                                  </Link>
                                              ))}
                                          </div>
                                      </div>
                                  ) : (
                                      <div className="flex flex-col items-center justify-center h-full py-12 text-slate-400">
                                          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                                              <Search size={24} className="text-slate-300" />
                                          </div>
                                          <p className="font-medium text-slate-500">No matches found for "{menuSearchQuery}"</p>
                                          <p className="text-sm mt-1">Try checking for typos or using different keywords.</p>
                                      </div>
                                  );
                              })()}
                            </div>
                          ) : (
                            // Standard Column View
                            <div className="flex flex-row p-8 gap-8">

                              {/* Left Content Banner */}
                              {item.megaMenu.leftContent && (
                                <div className="w-64 flex-shrink-0 bg-slate-50 rounded-xl p-6 flex flex-col h-full border border-slate-100">
                                  {item.megaMenu.leftContent.badgeText && (
                                    <span className="inline-block px-2 py-1 bg-yellow-400 text-slate-900 text-[10px] font-bold rounded mb-4 w-fit">
                                      {item.megaMenu.leftContent.badgeText}
                                    </span>
                                  )}
                                  <h3 className="font-bold text-lg text-slate-900 mb-2 leading-tight">
                                    {item.megaMenu.leftContent.title}
                                  </h3>
                                  <p className="text-sm text-slate-600 mb-6 leading-relaxed flex-grow">
                                    {item.megaMenu.leftContent.description}
                                  </p>
                                  {item.megaMenu.leftContent.image && (
                                    <img 
                                      src={item.megaMenu.leftContent.image} 
                                      alt="Feature" 
                                      className="w-full h-auto rounded-lg mix-blend-multiply"
                                    />
                                  )}
                                </div>
                              )}

                              {/* Columns */}
                              <div className="flex-1 grid grid-cols-5 gap-8">
                                {item.megaMenu.columns.map((column, idx) => (
                                  <div key={idx} className="space-y-6">
                                    {column.groups ? (
                                      // Render multiple groups in one column
                                      column.groups.map((group, gIdx) => (
                                        <div key={gIdx} className="space-y-4">
                                          {group.title ? (
                                            <h4 className="text-[15px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block">
                                              {group.title}
                                            </h4>
                                          ) : group.title === "" ? (
                                            // Render spacer if empty string
                                            <h4 className="text-[15px] font-bold text-transparent border-b-2 border-transparent pb-1 inline-block select-none" aria-hidden="true">
                                              &nbsp;
                                            </h4>
                                          ) : null /* Render nothing if undefined/null */}

                                          <ul className="space-y-2.5">
                                            {group.items.map((subItem, sIdx) => (
                                              <li key={sIdx}>
                                                <Link
                                                  to={subItem.href}
                                                  onClick={() => setActiveSubmenu(null)}
                                                  className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit after:absolute after:left-0 after:-bottom-1 after:h-[2px] after:w-full after:origin-left after:scale-x-0 after:bg-yellow-500 after:transition-transform after:duration-300 hover:after:scale-x-100 block"
                                                >
                                                  {subItem.title}
                                                </Link>
                                              </li>
                                            ))}
                                          </ul>
                                        </div>
                                      ))
                                    ) : (
                                      // Render standard single column
                                      <div className="space-y-4">
                                        {column.title ? (
                                          <h4 className="text-[15px] font-bold text-slate-900 border-b-2 border-yellow-400 pb-1 inline-block">
                                            {column.title}
                                          </h4>
                                        ) : column.title === "" ? (
                                          /* Spacer for alignment if empty string */
                                          <h4 className="text-[15px] font-bold text-transparent border-b-2 border-transparent pb-1 inline-block select-none" aria-hidden="true">
                                            &nbsp;
                                          </h4>
                                        ) : null /* Render nothing if undefined/null */}

                                        <ul className="space-y-2.5">
                                          {column.items?.map((subItem, sIdx) => (
                                            <li key={sIdx}>
                                              <Link
                                                to={subItem.href}
                                                onClick={() => setActiveSubmenu(null)}
                                                className="text-[14px] text-slate-600 hover:text-[#005eb8] transition-colors relative w-fit after:absolute after:left-0 after:-bottom-1 after:h-[2px] after:w-full after:origin-left after:scale-x-0 after:bg-yellow-500 after:transition-transform after:duration-300 hover:after:scale-x-100 block"
                                              >
                                                {subItem.title}
                                              </Link>
                                            </li>
                                          ))}
                                        </ul>
                                      </div>
                                    )}
                                  </div>
                                ))}
                              </div>

                              {/* Close Button */}
                              <button
                                onClick={(e) => { e.stopPropagation(); setActiveSubmenu(null); }}
                                className="absolute top-6 right-4 text-slate-400 hover:text-slate-600 transition-colors"
                              >
                                <X size={20} />
                              </button>
                            </div>
                          )}
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>

                  {/* Regular Dropdown (Services/Simple) */}
                  <AnimatePresence>
                    {item.children && !item.megaMenu && activeSubmenu === item.title && (
                      <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: 10 }}
                        transition={{ duration: 0.2 }}
                        className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-100 py-2 z-50"
                      >
                        {item.children.map((subItem) => (
                          <Link
                            key={subItem.title}
                            to={subItem.href}
                            onClick={() => setActiveSubmenu(null)}
                            className="block px-4 py-2.5 text-sm text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors"
                          >
                            {subItem.title}
                          </Link>
                        ))}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              ))}
            </div>
          </div>

          {/* Right Side Actions (Search + Contact) */}
          <div className="hidden lg:flex items-center gap-3">
            <button
              className="p-2.5 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            <button className="relative overflow-hidden group bg-yellow-400 hover:bg-yellow-500 text-white font-bold p-3 transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-[0_8px_20px_-6px_rgba(250,204,21,0.6)] active:translate-y-0 active:shadow-none">
              <span className="relative z-10 flex items-center text-slate-900">
                Contact Us
              </span>
              <div className="absolute top-0 left-[-100%] w-[40%] h-full bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-[-20deg] group-hover:animate-shimmer"></div>
            </button>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2">
            <button
              className="p-2 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={22} />
            </button>

            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div 
            initial={{ opacity: 0, x: "100%" }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: "100%" }}
            transition={{ type: "tween", duration: 0.3 }}
            className="lg:hidden fixed inset-0 z-50 bg-white"
          >
            <div className="flex flex-col h-full">
              <div className="flex items-center justify-between p-4 border-b border-gray-100">
                <div className="flex items-center gap-2">
                  <img src="https://www.gnjworldwide.com/Logo.png" className="h-10 w-auto" alt="Logo" />
                  <span className="font-bold text-lg text-slate-900">GnJ<span className="text-yellow-500">Worldwide</span></span>
                </div>
                <button
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="p-2 text-slate-500 hover:bg-slate-100 rounded-full"
                >
                  <X size={24} />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto py-4 px-4 space-y-2">
                {NAV_ITEMS.map((item) => (
                  <div key={item.title} className="border-b border-gray-50 last:border-0 pb-2">
                    <div
                      className="flex items-center justify-between w-full px-4 py-3 text-base font-semibold text-slate-800 rounded-xl hover:bg-slate-50 cursor-pointer active:bg-slate-100 transition-colors"
                      onClick={() => {
                        if (item.children || item.megaMenu) {
                          setActiveSubmenu(activeSubmenu === item.title ? null : item.title);
                        } else {
                          setIsMobileMenuOpen(false);
                        }
                      }}
                    >
                      {item.children || item.megaMenu ? (
                        <span>{item.title}</span>
                      ) : (
                        <Link to={item.href} onClick={() => setIsMobileMenuOpen(false)}>
                          {item.title}
                        </Link>
                      )}

                      {(item.children || item.megaMenu) && (
                        <motion.div
                          animate={{ rotate: activeSubmenu === item.title ? 180 : 0 }}
                        >
                          <ChevronDown className={`w-5 h-5 text-slate-400 ${activeSubmenu === item.title ? 'text-yellow-500' : ''}`} />
                        </motion.div>
                      )}
                    </div>

                    {/* Mobile Submenu Rendering */}
                    <AnimatePresence>
                      {activeSubmenu === item.title && (
                        <motion.div 
                          initial={{ height: 0, opacity: 0 }}
                          animate={{ height: "auto", opacity: 1 }}
                          exit={{ height: 0, opacity: 0 }}
                          className="pl-4 pr-2 overflow-hidden"
                        >
                          <div className="py-2 space-y-1">
                            {item.megaMenu ? (
                              item.megaMenu.columns.map((col, idx) => (
